  if ($signed(s_exponent) <= -126) begin 
  sout_PackSum[30 : 23] <= 0; 
  sout_PackSum[22:0] <= 0; 
  end 
  if ($signed(s_exponent) > 127) begin 
  sout_PackSum[22 : 0] <= 0; 
  sout_PackSum[30 : 23] <= 255; 
  sout_PackSum[31] <= s_sign; 
  end 
  end 
  else begin 
  sout_PackSum <= sout_NormaliseSum; 
  end 
 end 
