		end
	S_On1: begin
		X = 1;
		StateNext = S_On2;
		end
	S_On2: begin
		X = 1;
		StateNext = S_On3;
		end
	S_On3: begin
		X = 1;
		StateNext = S_Off;
		end
  endcase
end

always @(posedge Clk) begin
  if (Rst == 1)
	State <= S_Off;
  else 
	State <= StateNext;
end

endmodule

