module autovcoder_022804 (
    // inputs:
    atm_valid,
    dtm_valid,
    itm_valid,

    // outputs:
    compute_tm_count
);

  output [1:0] compute_tm_count;
  input atm_valid;
  input dtm_valid;
  input itm_valid;

  reg  [1:0] compute_tm_count;
  wire [2:0] switch_for_mux;
  assign switch_for_mux = {itm_valid, atm_valid, dtm_valid};
  always @(switch_for_mux) begin
    case (switch_for_mux)

      3'b000: begin
        compute_tm_count = 0;
      end  // 3'b000 

      3'b001: begin
        compute_tm_count = 1;
      end  // 3'b001 

      3'b010: begin
        compute_tm_count = 1;
      end  // 3'b010 

      3'b011: begin
        compute_tm_count = 2;
      end  // 3'b011 

      3'b100: begin
        compute_tm_count = 1;
      end  // 3'b100 

      3'b101: begin
        compute_tm_count = 2;
      end  // 3'b101 

      3'b110: begin
        compute_tm_count = 2;
      end  // 3'b110 

      3'b111: begin
        compute_tm_count = 3;
      end  // 3'b111 

    endcase  // switch_for_mux
  end



endmodule

