module autovcoder_078990 (
    input W0_clk,
    input [9:0] W0_addr,
    input W0_en,
    input [31:0] W0_data,
    input [3:0] W0_mask,
    input R0_clk,
    input [9:0] R0_addr,
    input R0_en,
    output [31:0] R0_data
);

  reg reg_R0_ren;
  reg [9:0] reg_R0_addr;
  reg [31:0] ram[1023:0];
`ifdef RANDOMIZE_MEM_INIT
  integer initvar;
  initial begin
    #`RANDOMIZE_DELAY begin
    end
    for (initvar = 0; initvar < 1024; initvar = initvar + 1) ram[initvar] = {1{$random}};
    reg_R0_addr = {1{$random}};
  end
`endif
  integer i;
  always @(posedge R0_clk) reg_R0_ren <= R0_en;
  always @(posedge R0_clk) if (R0_en) reg_R0_addr <= R0_addr;
  always @(posedge W0_clk)
    if (W0_en) begin
      if (W0_mask[0]) ram[W0_addr][7:0] <= W0_data[7:0];
      if (W0_mask[1]) ram[W0_addr][15:8] <= W0_data[15:8];
      if (W0_mask[2]) ram[W0_addr][23:16] <= W0_data[23:16];
      if (W0_mask[3]) ram[W0_addr][31:24] <= W0_data[31:24];
    end
`ifdef RANDOMIZE_GARBAGE_ASSIGN
  reg [31:0] R0_random;
`ifdef RANDOMIZE_MEM_INIT
  initial begin
    #`RANDOMIZE_DELAY begin
    end
    R0_random  = {$random};
    reg_R0_ren = R0_random[0];
  end
`endif
  always @(posedge R0_clk) R0_random <= {$random};
  assign R0_data = reg_R0_ren ? ram[reg_R0_addr] : R0_random[31:0];
`else
  assign R0_data = ram[reg_R0_addr];
`endif

endmodule

