    end else begin
        sda_out <= 1'bz;
    end
end

always @(posedge I_clk) begin
    out_en_dly <= out_en;
    if (out_en_dly) begin
        // Process the received data and update temperature and humidity
        temperature <= 32'h12345678;
        humidity <= 32'h87654321;
    end
end

assign I_O_sda = sda_out;

assign O_num1 = temperature[3:0];
assign O_num2 = temperature[7:4];
assign O_num3 = temperature[11:8];
assign O_num4 = temperature[15:12];

assign O_num5 = humidity[3:0];
