        else if (read_enable)
            rdata_valid <= 1'b1;
        else
            rdata_valid <= 1'b0;
    end

    always @(posedge clk) begin
        if (rst)
            read_ptr <= 5'b00000;
        else if (read_enable)
            read_ptr <= read_ptr + 5'b00001;
    end

    always @(posedge clk) begin
        if (write_enable)
