      else if (b >= a && b >= c && c >= a)
      begin
         max <= b ; 
         mid <= c ; 
         min <= a ; 
      end
      else if (c >= a && c >= b && a >= b)
      begin
         max <= c ; 
         mid <= a ; 
         min <= b ; 
      end
      else if (c >= a && c >= b && b >= a)
      begin
         max <= c ; 
         mid <= b ; 
         min <= a ; 
      end 
   end 
endmodule

