  (* altera_attribute = "-name auto_shift_register_recognition OFF" *) reg [INPUT2_WIDTH_WITH_SIGN - 1 : 0] reg_datab2; 
 generate 
 if(INPUT1_WIDTH>=19 && INPUT1_WIDTH<=27 && INPUT2_WIDTH>=19 && INPUT2_WIDTH<=27) 
 begin 
  always@(posedge clock) 
  begin 
  if (enable) 
  begin 
  reg_dataa <= dataa; 
  reg_datab <= datab; 
  end 
