  POR_RFRST: begin 
  rPOR_nxt_state <= POR_RLOOP; 
  end 
  POR_RLOOP: begin 
  rPOR_nxt_state <= (wJOBDone)? ((iStart)? POR_RFRST:POR_READY):POR_RLOOP; 
