  always @ (posedge iSystemClock, posedge iReset) begin 
  if (iReset) begin 
  rReady <= 0; 
  rTimer[3:0] <= 0; 
  rPO_Reset <= 0; 
  end else begin 
  case (rPOR_nxt_state) 
  POR_RESET: begin 
  rReady <= 0; 
  rTimer[3:0] <= 0; 
  rPO_Reset <= 0; 
  end 
  POR_READY: begin 
  rReady <= 1; 
  rTimer[3:0] <= 0; 
  rPO_Reset <= 0; 
  end 
  POR_RFRST: begin 
  rReady <= 0; 
  rTimer[3:0] <= 4'b0000; 
  rPO_Reset <= 1; 
  end 
  POR_RLOOP: begin 
  rReady <= 0; 
  rTimer[3:0] <= rTimer[3:0] + 1'b1; 
  rPO_Reset <= 1; 
  end 
  endcase 
  end 
  end 
  assign oReady = rReady | wJOBDone ; 
  assign oLastStep = wJOBDone ; 
  assign oPO_Reset = rPO_Reset ; 
 endmodule

