    end
  end

  integer i;
  always @(posedge sclk) begin
    if (sclk_en) begin
      if (push) begin
        for (i = 0; i < DEPTH - 1; i = i + 1) begin
          mem[i+1] <= mem[i];
        end
        mem[0] <= data;
      end
    end
  end
endmodule

