module origen_027718 (
    input wire nrst,
    input wire clk_lvds,
    input wire coax_in,
    input wire [7:0] deadticks,
    input wire [7:0] firingticks,
    input wire clk_test,
    input wire [7:0] phaseoffset,
    input wire clkin,
    input wire usefullwidth,
    input wire passthrough,
    input wire resethist,
    input wire vetopmtlast,
    input wire [3:0] lvds_rx,
    output reg [3:0] led,
    output reg coax_out,
    output reg [15:0] histo [0:3]
);

    // Test signal generation
    reg [5:0] test_counter;
    reg pmt1test;

    always @(posedge clk_test or negedge nrst) begin
        if (!nrst)
            test_counter <= 6'b0;
        else
            test_counter <= test_counter + 1'b1;
    end

    always @(posedge clk_test or negedge nrst) begin
        if (!nrst)
            pmt1test <= 1'b0;
        else
            pmt1test <= (test_counter == 6'b0);
    end

    // Edge detection
    reg [3:0] lvds_rx_d;
    wire [3:0] edge_detect;

    always @(posedge clk_lvds) begin
        lvds_rx_d <= lvds_rx;
    end

    assign edge_detect = lvds_rx & ~lvds_rx_d;

    // Phase offset and width control
    reg [7:0] phase_counter;
    reg [3:0] processed_output;

    always @(posedge clk_lvds or negedge nrst) begin
        if (!nrst) begin
            phase_counter <= 8'b0;
            processed_output <= 4'b0;
        end else begin
            phase_counter <= phase_counter + 1'b1;
            if (phase_counter == phaseoffset) begin
                processed_output <= edge_detect;
                if (!usefullwidth)
                    processed_output <= 4'b0;
            end
        end
    end

    // Histogram generation
    integer i;
    always @(posedge clk_lvds or negedge nrst) begin
        if (!nrst) begin
            for (i = 0; i < 4; i = i + 1)
                histo[i] <= 16'b0;
        end else if (resethist) begin
            for (i = 0; i < 4; i = i + 1)
                histo[i] <= 16'b0;
        end else begin
            for (i = 0; i < 4; i = i + 1)
                if (edge_detect[i] && !vetopmtlast)
                    histo[i] <= histo[i] + 1'b1;
        end
    end

    // Output mapping
    always @(posedge clk_lvds or negedge nrst) begin
        if (!nrst) begin
            led <= 4'b0;
            coax_out <= 1'b0;
        end else if (passthrough) begin
            led <= lvds_rx;
            coax_out <= coax_in;
        end else begin
            led[0] <= processed_output[0];
            led[1] <= processed_output[1];
            led[2] <= processed_output[2];
            led[3] <= pmt1test;
            coax_out <= processed_output[0] | pmt1test | clkin;
        end
    end

endmodule

