            pipe_tx_deemph_r2 <= #TCQ 1'b0;
            pipe_tx_margin_r2 <= #TCQ 1'b0;
            pipe_tx_swing_r2 <= #TCQ 1'b0;

            pipe_tx_rcvr_det_o <= #TCQ 1'b0;
