    input [7:0] s, m, h, d, me, a,
    input en, rst,
    output reg AD, CS, RD, WR,
    output reg Listo_inicio,
    output reg [7:0] Dato
);

always @(posedge rst or posedge en) begin
    if (rst) begin
        AD <= 1;
        CS <= 1;
        RD <= 1;
        WR <= 1;
        Dato <= 0;
        Listo_inicio <= 0;
    end
    else if (en) begin
        case (addr)
            6'd1: begin
                AD <= 0;
                Dato <= 0;
            end
            6'd2: begin
                AD <= 0;
                CS <= 0;
                RD <= 1;
                WR <= 0;
                Dato <= 8'h02;
            end
            6'd3: begin
                Dato <= 8'h02;
            end
            6'd4: begin
                AD <= 1;
                CS <= 0;
                RD <= 1;
                WR <= 0;
                Dato[4] <= 1;
            end
            6'd5: begin
                Dato[4] <= 1;
            end
            6'd6: begin
                AD <= 1;
                CS <= 0;
                RD <= 1;
                WR <= 0;
                Dato[4] <= 0;
            end
            6'd7: begin
                Dato[4] <= 0;
            end
            6'd8: begin
                AD <= 0;
                Dato <= 0;
            end
            6'd9: begin
                AD <= 0;
                CS <= 0;
                RD <= 1;
                WR <= 0;
                Dato <= 8'h10;
            end
            6'd10: begin
                Dato <= 8'h10;
            end
            6'd11: begin
                AD <= 1;
                CS <= 0;
                RD <= 1;
                WR <= 0;
                Dato <= 8'hd2;
            end
            6'd12: begin
