                Listo_inicio <= 1;
            end
            default: begin
                AD <= 1;
                CS <= 1;
                RD <= 1;
                WR <= 1;
                Dato <= 0;
            end
        endcase
    end
    else begin
        AD <= 1;
        CS <= 1;
