 reg [23:0] acc3_d1; 
 reg [23:0] acc3_d2; 
 reg [23:0] diff1; 
 reg [23:0] diff2; 
 reg [23:0] diff3; 
 reg [23:0] diff1_d; 
 reg [23:0] diff2_d; 
 reg [7:0] word_count; 
 reg word_clk; 
 assign data_rdy_o = word_clk; 
 always @(mdata_i) 
 begin 
  if(mdata_i == 0) 
  begin 
  ip_data1 <= 0; 
  end 
  else 
  begin 
  ip_data1 <= 1; 
  end 
 end 
 always @(negedge mclkout_i or posedge reset_i) 
 begin 
  if( reset_i == 1'b1 ) 
  begin 
  acc1 <= 0; 
  acc2 <= 0; 
  acc3 <= 0; 
  end 
  else 
  begin 
  acc1 <= acc1 + ip_data1; 
  acc2 <= acc2 + acc1; 
  acc3 <= acc3 + acc2; 
  end 
 end 
 always@(posedge mclkout_i or posedge reset_i ) 
 begin 
  if(reset_i == 1'b1) 
  begin 
  word_count <= 0; 
  end 
  else 
  begin 
  word_count <= word_count + 1; 
  end 
 end 
 always @(word_count) 
 begin 
  word_clk <= word_count[7]; 
