 always @(posedge word_clk or posedge reset_i) 
 begin 
  if(reset_i == 1'b1) 
  begin 
  acc3_d2 <= 0; 
  diff1_d <= 0; 
  diff2_d <= 0; 
  diff1 <= 0; 
  diff2 <= 0; 
  diff3 <= 0; 
  end 
  else 
  begin 
  diff1 <= acc3 - acc3_d2; 
  diff2 <= diff1 - diff1_d; 
  diff3 <= diff2 - diff2_d; 
  acc3_d2 <= acc3; 
  diff1_d <= diff1; 
  diff2_d <= diff2; 
  end 
 end 
 always @(posedge word_clk) 
 begin 
  data_o[15] <= diff3[23]; 
  data_o[14] <= diff3[22]; 
  data_o[13] <= diff3[21]; 
  data_o[12] <= diff3[20]; 
  data_o[11] <= diff3[19]; 
  data_o[10] <= diff3[18]; 
  data_o[9] <= diff3[17]; 
  data_o[8] <= diff3[16]; 
  data_o[7] <= diff3[15]; 
  data_o[6] <= diff3[14]; 
  data_o[5] <= diff3[13]; 
  data_o[4] <= diff3[12]; 
  data_o[3] <= diff3[11]; 
  data_o[2] <= diff3[10]; 
  data_o[1] <= diff3[9]; 
  data_o[0] <= diff3[8]; 
 end 
 endmodule

