module rtlpp_11407 (
    address,
    chipselect,
    clk,
    in_port,
    reset_n,
    write_n,
    writedata,
    irq,
    readdata
);

  output           irq;
  output  [31:0]   readdata;
  input   [1:0]    address;
  input            chipselect;
  input            clk;
  input   [3:0]    in_port;
  input            reset_n;
  input            write_n;
  input   [31:0]   writedata;

  wire    clk_en;
  reg     [3:0]    d1_data_in;
  reg     [3:0]    d2_data_in;
  wire    [3:0]    data_in;
  reg     [3:0]    edge_capture;
