localparam MASTER_0 = 0;
localparam MASTER_1 = 1;

always @(posedge clk) begin
  if (rst) begin
    master_select <= MASTER_NO_SEL;
  end else begin
    case (master_select)
      MASTER_0: begin
        if (~i_m0_cyc && ~i_s_ack) begin
          master_select <= MASTER_NO_SEL;
        end
      end
      MASTER_1: begin
        if (~i_m1_cyc && ~i_s_ack) begin
          master_select <= MASTER_NO_SEL;
        end
      end
      default: begin
        if (i_m0_cyc) begin
          master_select <= MASTER_0;
