 assign read = retire_reg && !empty && !recover && !hazard_stall; 
 always @(posedge clk or negedge rst) begin 
  if (!rst) begin 
  head <= 4'h0; 
  end 
  else if (read) begin 
  head <= head + 1; 
  end 
