  tail <= 4'h0; 
  else if (dec_tail) 
  tail <= tail - 1; 
  else if (write) begin 
  tail <= tail + 1; 
  rob[tail] <= {RegDest, isSW, rd_DP, PR_old_DP, PR_new_DP}; 
