            DBDataSrc = 1'b0;
            InsMemRW = 1'b0;
        end

        `OP_BEQ: begin
            PCWre = 1'b1;
            PCSrc = (zero) ? 2'b01 : 2'b00;
            ExtSel = 1'b1;
            ALUSrcA = 1'b0;
            ALUSrcB = 1'b0;
            ALUOp = `ALU_SUB;
            RegWre = 1'b0;
            mRD = 1'b0;
            mWR = 1'b0;
            DBDataSrc = 1'b0;
            InsMemRW = 1'b0;
        end

