module rtlpp_11236(
    input clk,
    input slow_clk,
    input block_enable,
    input pdm_in,
    output reg outValid,
    output reg [3:0] encPcm
);

reg clk_enable;
reg rst;
reg inValid;
wire signed [15:0] filter_out;
reg signed [1:0] filter_in;

always @(*) begin
    filter_in = {(~pdm_in), 1'b1};
end

`define IDLE 2'd0
`define TRANSITION 2'd1
`define COMPRESS 2'd2

reg [1:0] state, next_state;

always @(*) begin
    case(state)
        `IDLE: begin
            if (block_enable)
                next_state = `TRANSITION;
            else
                next_state = `IDLE;
        end
        `TRANSITION: begin
            next_state = `COMPRESS;
        end
        `COMPRESS: begin
            if (!block_enable)
                next_state = `IDLE;
            else
                next_state = `COMPRESS;
        end
        default: next_state = `IDLE;
    endcase
end

always @(posedge clk) begin
    state <= next_state;
end

always @(*) begin
    case(state)
        `IDLE: begin
            clk_enable = 0;
            rst = 1;
        end
        `TRANSITION: begin
            clk_enable = 0;
            rst = 0;
        end
        `COMPRESS: begin
            clk_enable = 1;
            rst = 0;
        end
        default: begin
            clk_enable = 0;
            rst = 1;
        end
    endcase
end

