    if (rst) begin
        integrator1 <= 16'd0;
        integrator2 <= 16'd0;
        integrator3 <= 16'd0;
        integrator4 <= 16'd0;
        comb1 <= 16'd0;
        comb2 <= 16'd0;
        comb3 <= 16'd0;
        comb4 <= 16'd0;
    end else if (clk_enable) begin
        integrator1 <= integrator1 + filter_in;
        integrator2 <= integrator2 + integrator1;
        integrator3 <= integrator3 + integrator2;
        integrator4 <= integrator4 + integrator3;
        comb1 <= integrator4 - comb4;
        comb2 <= comb1 - comb3;
        comb3 <= comb2 - comb2;
        comb4 <= comb3 - comb1;
    end
