reg [3:0] step_index;
reg [15:0] predsample;
reg [3:0] indexTable[0:7];
reg [7:0] stepSizeTable[0:89];

initial begin
    indexTable[0] = 0; indexTable[1] = 1; indexTable[2] = 2; indexTable[3] = 5;
    indexTable[4] = 8; indexTable[5] = 4; indexTable[6] = 6; indexTable[7] = 9;
    // Initialize the stepSizeTable with proper values
end

always @(posedge slow_clk or posedge rst) begin
    if (rst) begin
        step_index <= 4'd0;
        predsample <= 16'd0;
    end else if (inValid) begin
