                if (counter >= baudRate) begin
                    next_Tx = TxD[3];
                    next_EvenParityBit = EvenParityBit ^ TxD[3];
                    next_TXstate = Data4;
                end
            end

            Data4: begin
                if (counter >= baudRate) begin
                    next_Tx = TxD[4];
                    next_EvenParityBit = EvenParityBit ^ TxD[4];
                    if (ctrl[7:6] != 2'b00) begin
                        next_TXstate = Data5;
                    end
                    else begin
                        next_TXstate = TXafterDataState;
                    end
                end
