module autovcoder_079253 (
    // Inputs
      input       clk_i
    , input       rst_i
    , input       hold_i
    , input [3:0] request_i

    // Outputs
    , output [3:0] grant_o
);


  //-----------------------------------------------------------------
  // Registers / Wires
  //-----------------------------------------------------------------
  wire [3:0] req_ffs_masked_w;
  wire [3:0] req_ffs_unmasked_w;
  wire [3:0] req_ffs_w;

  reg  [3:0] mask_next_q;
  reg  [3:0] grant_last_q;
  wire [3:0] grant_new_w;

  //-----------------------------------------------------------------
  // ffs: Find first set
  //-----------------------------------------------------------------
  function [3:0] ffs;
    input [3:0] request;
    begin
      ffs[0] = request[0];
      ffs[1] = ffs[0] | request[1];
      ffs[2] = ffs[1] | request[2];
      ffs[3] = ffs[2] | request[3];
    end
  endfunction

  assign req_ffs_masked_w = ffs(request_i & mask_next_q);
  assign req_ffs_unmasked_w = ffs(request_i);

  assign req_ffs_w = (|req_ffs_masked_w) ? req_ffs_masked_w : req_ffs_unmasked_w;

  always @(posedge clk_i)
    if (rst_i == 1'b1) begin
      mask_next_q  <= {4{1'b1}};
      grant_last_q <= 4'b0;
    end else begin
      if (~hold_i) mask_next_q <= {req_ffs_w[2:0], 1'b0};

      grant_last_q <= grant_o;
    end

  assign grant_new_w = req_ffs_w ^ {req_ffs_w[2:0], 1'b0};
  assign grant_o = hold_i ? grant_last_q : grant_new_w;


endmodule

files.autovcoder_094208.v:
module autovcoder_094208 #(
    parameter FAMILY = "common",
    parameter DATA_WIDTH = 36,
    parameter REGMODE = "noreg",
    parameter WRITE_MODE = "normal"
) (
    input clk_i,
    input clk_en_i,
    input wr_en_i,
    input rst_i,
    input [(DATA_WIDTH - 1):0] wr_data_i,
    input [(DATA_WIDTH - 1):0] mem_out_i,
    output [(DATA_WIDTH - 1):0] rd_data_o
);
  if ((WRITE_MODE == "write-through")) begin : WRITE_THROUGH
    reg [(DATA_WIDTH - 1):0] wr_data_p_r;
    reg wr_en_p_r;
    always @(posedge clk_i or posedge rst_i) begin
      if (rst_i) begin
        wr_data_p_r <= {DATA_WIDTH{1'b0}};
        wr_en_p_r   <= 1'b0;
      end else begin
        wr_data_p_r <= wr_data_i;
        wr_en_p_r   <= wr_en_i;
      end
    end
    if ((REGMODE == "noreg")) begin : _NREG
      assign rd_data_o = (wr_en_p_r ? wr_data_p_r : mem_out_i);
    end else begin : _REG
      reg  [(DATA_WIDTH - 1):0] rd_data_r;
      wire [(DATA_WIDTH - 1):0] rd_data_nxt_w = (wr_en_p_r ? wr_data_p_r : mem_out_i);
      assign rd_data_o = rd_data_r;
      always @(posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
          rd_data_r <= {DATA_WIDTH{1'b0}};
        end else begin
          rd_data_r <= rd_data_nxt_w;
        end
      end
    end
  end else begin : NORMAL
    assign rd_data_o = mem_out_i;
  end
endmodule

files.autovcoder_071244.v:
module autovcoder_071244 #(
    parameter MW = 2
) (
    input            clk,
    input            rst,
    input            cenop,
    input            zero,
    input      [7:0] start_value,
    input            load,
    input            clr_flag,
    output reg       flag,
    output reg       overflow
);

  reg [7:0] cnt, next, init;
  reg [MW-1:0] free_cnt, free_next;
  reg load_l, free_ov;

  always @(posedge clk)
    if (clr_flag || rst) flag <= 1'b0;
    else if (cenop && zero && load && overflow) flag <= 1'b1;

  always @(*) begin
    {free_ov, free_next} = {1'b0, free_cnt} + 1'b1;
    /* verilator lint_off WIDTH */
    {overflow, next} = {1'b0, cnt} + free_ov;
    /* verilator lint_on WIDTH */
    init = start_value;
  end

  always @(posedge clk) begin
    load_l <= load;
    if ((!load_l && load) || rst) begin
      cnt <= start_value;
    end else if (cenop && zero && load) begin
      cnt <= overflow ? init : next;
    end
  end

  // Free running counter, resetting
  // the value of this part with the load
  // event can slow down music, vg Bad Dudes
  always @(posedge clk) begin
    if (rst) begin
      free_cnt <= 0;
    end else if (cenop && zero) begin
      free_cnt <= free_next;
    end
  end

endmodule

