        end
        else begin
            if (wb_stall) begin
                // Maintain previous values
            end
            else if (me_stall) begin
                wb_reg_write <= 1'b0;
                wb_mem_to_reg <= me_mem_to_reg;
                wb_data_memory <= me_mem_read_data;
                wb_alu_result <= me_alu_result;
                wb_rt_rd <= me_rt_rd;
