files.autovcoder_136938.v:
module autovcoder_136938 (  
    input clk,  
    input reset,  
    input [3:0] data_in,  
    input send,  
    output reg ack,  
    output reg [3:0] data_out  
);  

    reg [1:0] state;  
    reg [1:0] next_state;  

    parameter IDLE = 2'b00;  
    parameter SEND = 2'b01;  
    parameter WAIT_ACK = 2'b10;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            state <= IDLE;  
        else  
            state <= next_state;  
    end  

    always @(state or send or ack) begin  
        case (state)  
            IDLE: begin  
                if (send) begin  
                    next_state = SEND;  
                    ack = 0;  
                end else begin  
                    next_state = IDLE;  
                end  
            end  
            SEND: begin  
                next_state = WAIT_ACK;  
                data_out = data_in;  
            end  
            WAIT_ACK: begin  
                if (ack) begin  
                    next_state = IDLE;  
                end else begin  
                    next_state = WAIT_ACK;  
                end  
            end  
            default: next_state = IDLE;  
        endcase  
    end  

    always @(posedge clk) begin  
        if (state == WAIT_ACK)  
            ack <= 1;  
    end  
endmodule

files.origen_160767.v:
module origen_160767(
    input ID_branch,
    input IDEX_regWrite,
    input EXMEM_regWrite,
    input EXMEM_memRead,
    input clk,
    input [4:0] EX_regDst,
    input [4:0] EXMEM_regRd,
    input [4:0] ID_regRt,
    input [4:0] ID_regRs,
    output reg forward1,
    output reg forward2,
    output reg PCWrite,
    output reg IFID_write,
    output reg ID_flush
);

    always @(negedge clk) begin
        // Initialize output signals
        forward1 = 0;
        forward2 = 0;
        PCWrite = 1;
        IFID_write = 1;
        ID_flush = 0;

        // Check for branch hazards
        if (ID_branch && IDEX_regWrite) begin
            if (EX_regDst == ID_regRs || EX_regDst == ID_regRt) begin
                PCWrite = 0;
                IFID_write = 0;
                ID_flush = 1;
            end
        end

        if (ID_branch && EXMEM_regWrite && !EXMEM_memRead) begin
            if (EXMEM_regRd == ID_regRs) begin
                forward1 = 1;
            end
            if (EXMEM_regRd == ID_regRt) begin
                forward2 = 1;
            end
        end

        if (ID_branch && EXMEM_memRead) begin
            if (EXMEM_regRd == ID_regRs || EXMEM_regRd == ID_regRt) begin
                PCWrite = 0;
                IFID_write = 0;
                ID_flush = 1;
            end
        end
    end

endmodule

