module origen_157586(
    input [255:0] M,
    input [255:0] N,
    input clk,
    input rst_n,
    input start,
    output [255:0] V,
    output ready
);

    reg [256:0] D;
    reg [255:0] V_reg;
    reg [8:0] i;
    reg ready_reg;
    reg [255:0] next_V;
    reg [8:0] next_i;
    reg next_ready;

    always @(*) begin
        if (i == 256 || &i) begin
            next_V = V_reg;
        end else if (D[256]) begin
            next_V = {V_reg[254:0], 1'b0};
        end else begin
            next_V = D[255:0];
        end

        if (i == 256) begin
            next_i = 511;
        end else if (i == 511) begin
            next_i = 256;
        end else begin
            next_i = i + 1;
        end

        next_ready = (i == 256);
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n || start) begin
            V_reg <= M;
            i <= 0;
            ready_reg <= 0;
        end else begin
            V_reg <= next_V;
            i <= next_i;
            ready_reg <= next_ready;
        end
    end

    assign D = {1'b0, V_reg} - N;
    assign V = V_reg;
    assign ready = ready_reg;

endmodule

files.origen_002548.v:
module origen_002548 (
    input wire CLK,
    input wire enable,
    input wire done_period,
    input wire [1:0] pullup_procedure,
    output reg [20:0] to_pwm,
    output reg done_up,
    output reg done_down
);

    parameter interval_change = 1;
    parameter max = 180;
    parameter min = 80;

    reg [7:0] angle_count;

    always @(posedge CLK) begin
        if (!enable) begin
            angle_count <= max;
            done_up <= 0;
            done_down <= 0;
        end else if (done_period) begin
            case (pullup_procedure)
                2'b01: begin
                    if (angle_count > min) begin
                        angle_count <= angle_count - interval_change;
                        done_up <= 0;
                    end else begin
                        done_up <= 1;
                    end
                    done_down <= 0;
                end
                2'b10: begin
                    if (angle_count < max) begin
                        angle_count <= angle_count + interval_change;
                        done_down <= 0;
                    end else begin
                        done_down <= 1;
                    end
                    done_up <= 0;
                end
                default: begin
                    // Do nothing
                end
            endcase
        end
    end

    always @(*) begin
        to_pwm = (angle_count * 2000 / 180) + 1000;
    end

endmodule

files.origen_146015.v:
module origen_146015 (
    input wire clk,
    input wire [15:0] data_in,
    output reg pattern_detected
);

    // State encoding
    localparam S0 = 3'b000;
    localparam S1 = 3'b001;
    localparam S2 = 3'b010;
    localparam S3 = 3'b011;
    localparam S4 = 3'b100;

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge clk) begin
        current_state <= next_state;
    end

    // Next state logic and output logic
    always @(*) begin
        next_state = current_state;
        pattern_detected = 1'b0;

        case (current_state)
            S0: begin
                if (data_in[15:12] == 4'b1010) next_state = S4;
                else if (data_in[15] == 1'b1) next_state = S1;
            end
            S1: begin
                if (data_in[14:11] == 4'b0101) next_state = S4;
                else if (data_in[14] == 1'b0) next_state = S2;
                else next_state = S1;
            end
            S2: begin
                if (data_in[13:10] == 4'b1010) next_state = S4;
                else if (data_in[13] == 1'b1) next_state = S3;
                else next_state = S0;
            end
            S3: begin
                if (data_in[12:9] == 4'b0101) next_state = S4;
                else if (data_in[12] == 1'b0) next_state = S2;
                else next_state = S1;
            end
            S4: begin
                pattern_detected = 1'b1;
                next_state = S0;
            end
            default: next_state = S0;
        endcase
    end

endmodule

files.origen_055930.v:
module origen_055930 (
    input wire Start,
    input wire Clk,
    input wire Reset,
    input wire Tclear,
    input wire [31:0] Timeout,
    output reg T,
    output reg [31:0] I
);

    // State encoding
    localparam INITIAL = 1'b0;
    localparam WAIT = 1'b1;

    reg state, next_state;

    // State register
    always @(posedge Clk or posedge Reset) begin
        if (Reset)
            state <= INITIAL;
        else
            state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (state)
            INITIAL: next_state = (Start && !Tclear) ? WAIT : INITIAL;
            WAIT: next_state = (I == Timeout || Tclear) ? INITIAL : WAIT;
            default: next_state = INITIAL;
        endcase
    end

    // Output logic
    always @(posedge Clk or posedge Reset) begin
        if (Reset) begin
            I <= 32'b0;
            T <= 1'b0;
        end else begin
            case (state)
                INITIAL: begin
                    I <= 32'b0;
                    T <= 1'b0;
                end
                WAIT: begin
                    I <= I + 1;
                    if (I == Timeout) begin
                        T <= 1'b1;
                    end
                end
            endcase
        end
    end

endmodule

files.origen_084456.v:
module origen_084456 #(
    parameter INIVAL = 0,
    parameter BW = 8
) (
    input wire clk,
    input wire rst_n,
    input wire data_in,
    input wire pol,
    input wire refclk,
    input wire [BW-1:0] flt_rise_st,
    input wire [BW-1:0] flt_fall_st,
    output reg data_out,
    output reg act_edge,
    output reg inact_edge
);

reg [BW-1:0] flt_count;
wire flt_count_full;
wire [BW-1:0] flt_threshold;

assign flt_threshold = data_in ? flt_rise_st : flt_fall_st;
assign flt_count_full = (flt_count == {BW{1'b1}});

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= INIVAL;
        flt_count <= {BW{1'b0}};
        act_edge <= 1'b0;
        inact_edge <= 1'b0;
    end else if (refclk) begin
        if (data_in != data_out) begin
            if (flt_count_full) begin
                data_out <= data_in;
                flt_count <= ~flt_threshold;
                act_edge <= data_in ^ ~pol;
                inact_edge <= ~data_in ^ ~pol;
            end else begin
                flt_count <= flt_count + 1'b1;
                act_edge <= 1'b0;
                inact_edge <= 1'b0;
            end
        end else begin
            flt_count <= ~flt_threshold;
            act_edge <= 1'b0;
            inact_edge <= 1'b0;
        end
    end else begin
        act_edge <= 1'b0;
        inact_edge <= 1'b0;
    end
end

endmodule

files.origen_058444.v:
module origen_058444(
    input clk,
    input in,
    input reset,
    input start,
    input pause,
    output reg [7:0] LEDG,
    output reg [2:0] state,
    output reg [0:0] value
);

    // State definitions
    parameter S0 = 3'b000;
    parameter S1 = 3'b001;
    parameter S2 = 3'b010;
    parameter S3 = 3'b011;

    // State transition logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= S0;
        end else begin
            case (state)
                S0: state <= in ? S1 : S0;
                S1: state <= in ? S2 : S1;
                S2: state <= in ? S3 : S2;
                S3: state <= in ? S0 : S3;
                default: state <= S0;
            endcase
        end
    end

    // LED output logic
    always @(posedge clk) begin
        if (value == 1'b0) begin
            case (state)
                S0: LEDG <= 8'hFF;
                S1: LEDG <= (clk) ? 8'hAA : 8'h55;
                S2: LEDG <= 8'h00;
                S3: LEDG <= (clk) ? 8'hF0 : 8'h0F;
                default: LEDG <= 8'hFF;
            endcase
        end
    end

    // Pause/Start control
    always @(posedge pause or posedge start) begin
        if (pause)
            value <= 1'b1;
        else if (start)
            value <= 1'b0;
    end

