module coreir_mux #(
    parameter width = 1
) (
    input [width-1:0] in0,
    input [width-1:0] in1,
    input sel,
    output [width-1:0] out
);
    assign out = sel ? in1 : in0;
endmodule

module commonlib_muxn__N2__width4 (
    input [3:0] in_data_0,
    input [3:0] in_data_1,
    input [0:0] in_sel,
    output [3:0] out
);
    wire [3:0] _join_out;
    coreir_mux #(
        .width(4)
    ) _join (
        .in0(in_data_0),
        .in1(in_data_1),
        .sel(in_sel[0]),
        .out(_join_out)
    );
    assign out = _join_out;
endmodule

module commonlib_muxn__N4__width4 (
    input [3:0] in_data_0,
    input [3:0] in_data_1,
    input [3:0] in_data_2,
    input [3:0] in_data_3,
    input [1:0] in_sel,
    output [3:0] out
);
    wire [3:0] _join_out;
    wire [3:0] muxN_0_out;
    wire [3:0] muxN_1_out;
    wire [0:0] sel_slice0_out;
    wire [0:0] sel_slice1_out;
    coreir_mux #(
        .width(4)
    ) _join (
        .in0(muxN_0_out),
        .in1(muxN_1_out),
        .sel(sel_slice1_out[0]),
        .out(_join_out)
    );
    commonlib_muxn__N2__width4 muxN_0 (
        .in_data_0(in_data_0),
        .in_data_1(in_data_1),
        .in_sel(sel_slice0_out),
        .out(muxN_0_out)
    );
    commonlib_muxn__N2__width4 muxN_1 (
        .in_data_0(in_data_2),
        .in_data_1(in_data_3),
        .in_sel(sel_slice0_out),
        .out(muxN_1_out)
    );
    coreir_slice #(
        .hi(1),
        .lo(0),
        .width(2)
    ) sel_slice0 (
        .in(in_sel),
        .out(sel_slice0_out)
    );
    coreir_slice #(
        .hi(2),
        .lo(1),
        .width(2)
    ) sel_slice1 (
        .in(in_sel),
        .out(sel_slice1_out)
    );
    assign out = _join_out;
endmodule

module Mux4x4 (
    input [3:0] I0,
    input [3:0] I1,
    input [3:0] I2,
    input [3:0] I3,
    input [1:0] S,
    output [3:0] O
);
    wire [3:0] mux_out;
    commonlib_muxn__N4__width4 mux (
        .in_data_0(I0),
        .in_data_1(I1),
        .in_data_2(I2),
        .in_data_3(I3),
        .in_sel(S),
        .out(mux_out)
    );
    assign O = mux_out;
endmodule

