    forever #5 clk = ~clk;
end

initial begin
    rst = 1;
    out_en = 0;
    #10 rst = 0;
    #50 out_en = 1;
    #100 $finish;
end

initial begin
    $monitor("Time=%0t rst=%b out_en=%b count=%b", $time, rst, out_en, count);
end

endmodule

