module origen_138752 (
    input wire clk,
    input wire reset,
    input wire [3:0] module1_out,
    input wire [3:0] module2_out,
    output wire [15:0] final_output
);

    wire [15:0] bcd_counter_out;
    wire [3:0] functional_out;

