        .clk(clk),
        .reset(reset),
        .q(bcd_counter_out)
    );

    functional_module func_mod (
        .bcd_ones(bcd_counter_out[3:0]),
        .module1_out(module1_out),
        .module2_out(module2_out),
        .result(functional_out)
    );

    assign final_output = {bcd_counter_out[15:4], functional_out};

